import React, { useState } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { analyzeImage } from './api';
import { ClipLoader } from 'react-spinners';

export default function MedicalImagingAnalyzer() {
  const [file, setFile] = useState(null);
  const [report, setReport] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [age, setAge] = useState('');
  const [sex, setSex] = useState('');

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (!file?.type.startsWith('image/')) {
      setError('Please upload a medical image (JPEG/PNG/DICOM)');
      return;
    }
    setFile(file);
    setError('');
  };

  const handleAnalysis = async () => {
    if (!file || !age || !sex) {
      setError('Please complete all required fields');
      return;
    }

    setLoading(true);
    try {
      const formData = new FormData();
      formData.append('file', file);
      formData.append('age', age);
      formData.append('sex', sex);

      const { analysis } = await analyzeImage(formData);
      setReport(analysis);
    } catch (err) {
      setError(err.message || 'Medical image analysis failed');
    } finally {
      setLoading(false);
    }
  };

  const MedicalReportRenderer = ({ content }) => {
    const extractNestedText = (children) => {
      if (typeof children === 'string') return children;
      return React.Children.toArray(children)
        .map(child => {
          if (typeof child === 'string') return child;
          if (child?.props?.children) return extractNestedText(child.props.children);
          return '';
        })
        .join(' ')
        .replace(/\s+/g, ' ')
        .trim();
    };

    return (
      <ReactMarkdown
        remarkPlugins={[remarkGfm]}
        components={{
          strong({ children }) {
            const rawText = extractNestedText(children);
            const certaintyMatch = rawText.match(
              /^(.*?)\s*\(?\b(Certainty:\s*\d{1,3}%)\b\)?$/i
            );

            console.log('Processing:', rawText); // Debug log

            if (certaintyMatch) {
              return (
                <span className="font-semibold text-diagnostic-dark dark:text-diagnostic-light">
                  {certaintyMatch[1].trim()}
                  <span className="ml-1.5 text-diagnostic-blue-600 dark:text-diagnostic-blue-400">
                    ({certaintyMatch[2]})
                  </span>
                </span>
              );
            }

            return <strong className="text-diagnostic-red">{children}</strong>;
          },
          ul: ({ children }) => (
            <ul className="ml-6 list-disc space-y-2 marker:text-diagnostic-blue-400">
              {children}
            </ul>
          ),
          li: ({ children }) => (
            <li className="text-diagnostic-dark/90 dark:text-diagnostic-light/80">
              {children}
            </li>
          ),
          h3: ({ children }) => (
            <h3 className="mt-8 mb-4 text-xl font-bold border-b pb-2 border-diagnostic-blue-200 dark:border-diagnostic-blue-800">
              {children}
            </h3>
          )
        }}
      >
        {content}
      </ReactMarkdown>
    );
  };

  return (
    <div className="max-w-4xl mx-auto p-6 bg-white dark:bg-diagnostic-dark rounded-xl shadow-medical dark:shadow-medical-dark">
      <h1 className="text-3xl font-bold text-center mb-8 text-diagnostic-blue-600 dark:text-diagnostic-blue-400">
        Medical Imaging Analysis Suite
      </h1>

      <div className="space-y-6">
        {/* File Upload Section */}
        <div className="space-y-3">
          <label className="block text-lg font-medium text-diagnostic-blue-600 dark:text-diagnostic-blue-400">
            Upload Medical Scan
          </label>
          <input
            type="file"
            onChange={handleFileChange}
            accept="image/*,.dcm"
            className="block w-full file:mr-4 file:py-3 file:px-6 file:border-0 file:rounded-lg file:bg-diagnostic-blue-600 file:text-white hover:file:bg-diagnostic-blue-700 dark:file:bg-diagnostic-blue-800 dark:hover:file:bg-diagnostic-blue-900 transition-colors"
          />
        </div>

        {/* Patient Information */}
        <div className="grid grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="block text-sm font-medium text-diagnostic-blue-600 dark:text-diagnostic-blue-400">
              Patient Age
            </label>
            <input
              type="number"
              value={age}
              onChange={(e) => setAge(e.target.value.replace(/\D/g, ''))}
              className="w-full p-3 rounded-lg border-2 border-diagnostic-blue-200 dark:border-diagnostic-blue-800 bg-white dark:bg-diagnostic-dark focus:ring-2 focus:ring-diagnostic-blue-500"
              placeholder="Age"
              min="0"
              max="120"
            />
          </div>
          <div className="space-y-2">
            <label className="block text-sm font-medium text-diagnostic-blue-600 dark:text-diagnostic-blue-400">
              Biological Sex
            </label>
            <select
              value={sex}
              onChange={(e) => setSex(e.target.value)}
              className="w-full p-3 rounded-lg border-2 border-diagnostic-blue-200 dark:border-diagnostic-blue-800 bg-white dark:bg-diagnostic-dark focus:ring-2 focus:ring-diagnostic-blue-500"
            >
              <option value="">Select</option>
              <option value="Male">Male</option>
              <option value="Female">Female</option>
              <option value="Other">Other</option>
            </select>
          </div>
        </div>

        {/* Analysis Trigger */}
        <button
          onClick={handleAnalysis}
          disabled={loading}
          className={`w-full py-4 px-8 rounded-lg font-bold text-white transition-colors ${
            loading ? 'bg-gray-400' : 'bg-diagnostic-blue-600 hover:bg-diagnostic-blue-700 dark:bg-diagnostic-blue-800 dark:hover:bg-diagnostic-blue-900'
          }`}
        >
          {loading ? (
            <div className="flex items-center justify-center gap-2">
              <ClipLoader color="#ffffff" size={24} />
              <span>Analyzing Medical Image...</span>
            </div>
          ) : (
            'Generate Diagnostic Report'
          )}
        </button>

        {/* Error Display */}
        {error && (
          <div className="p-4 bg-red-100 dark:bg-red-900/50 rounded-lg border border-red-200 dark:border-red-800 text-red-700 dark:text-red-200 flex items-center gap-2">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
            </svg>
            {error}
          </div>
        )}

        {/* Analysis Results */}
        {report && (
          <div className="mt-8 p-6 bg-white dark:bg-diagnostic-dark/95 rounded-xl shadow-medical border-2 border-diagnostic-blue-200 dark:border-diagnostic-blue-800">
            <h2 className="text-2xl font-bold mb-6 text-diagnostic-blue-600 dark:text-diagnostic-blue-400">
              AI Diagnostic Report
            </h2>
            <div className="prose medical-prose dark:medical-prose-invert max-w-none">
              <MedicalReportRenderer content={report} />
            </div>
            <div className="mt-6 p-4 bg-yellow-100 dark:bg-yellow-900/50 rounded-lg border border-yellow-200 dark:border-yellow-800 flex items-start gap-2">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 flex-shrink-0 text-yellow-600 dark:text-yellow-300" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
              </svg>
              <p className="text-sm text-yellow-800 dark:text-yellow-200">
                This AI-generated analysis requires clinical validation by a board-certified radiologist.
              </p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
